const e=JSON.parse('{"key":"v-cd85b4a0","path":"/learn-typescript/1.html","title":"start","lang":"zh-CN","frontmatter":{"title":"start","date":"2023-01-07T00:00:00.000Z","tag":["learn","TypeScript"],"category":["TypeScript"],"description":"learn","footer":true},"headers":[{"level":2,"title":"TypeScript 类型系统中的类型","slug":"typescript-类型系统中的类型","link":"#typescript-类型系统中的类型","children":[{"level":3,"title":"元组","slug":"元组","link":"#元组","children":[]},{"level":3,"title":"接口","slug":"接口","link":"#接口","children":[]},{"level":3,"title":"枚举","slug":"枚举","link":"#枚举","children":[]},{"level":3,"title":"字面量类型","slug":"字面量类型","link":"#字面量类型","children":[]},{"level":3,"title":"四种特殊类型","slug":"四种特殊类型","link":"#四种特殊类型","children":[]},{"level":3,"title":"类型的装饰","slug":"类型的装饰","link":"#类型的装饰","children":[]}]},{"level":2,"title":"TypeScript 类型系统中的类型运算","slug":"typescript-类型系统中的类型运算","link":"#typescript-类型系统中的类型运算","children":[{"level":3,"title":"条件类型（Conditional Type）：extends ? :","slug":"条件类型-conditional-type-extends","link":"#条件类型-conditional-type-extends","children":[]},{"level":3,"title":"推导 infer","slug":"推导-infer","link":"#推导-infer","children":[]},{"level":3,"title":"联合类型 ｜","slug":"联合类型","link":"#联合类型","children":[]},{"level":3,"title":"交叉类型 &","slug":"交叉类型","link":"#交叉类型","children":[]},{"level":3,"title":"映射类型","slug":"映射类型","link":"#映射类型","children":[]}]}],"git":{"createdTime":1673146488000,"updatedTime":1673242382000,"contributors":[{"name":"wangmaoquan","email":"1782976211@qq.com","commits":4}]},"readingTime":{"minutes":4.62,"words":1385},"filePathRelative":"learn-typescript/1.md","localizedDate":"2023年1月7日","excerpt":"<h2> TypeScript 类型系统中的类型</h2>\\n<p>静态类型系统的目的是把类型检查从运行时提前到编译时，那 TS 类型系统中肯定要把 JS 的运行时类型拿过来，也就是 <code>number、boolean、string、object、bigint、symbol、undefined、null</code> 这些类型，还有就是它们的包装类型 <code>Number、Boolean、String、Object、Symbol</code>。</p>\\n<p>这些很容易理解，给 JS 添加静态类型，总没有必要重新造一套基础类型吧，直接复用 JS 的基础类型就行。</p>\\n<p>复合类型方面，JS 有 class、Array，这些 TypeScript 类型系统也都支持，但是又多加了三种类型：<code>元组（Tuple）</code>、<code>接口（Interface）</code>、<code>枚举（Enum）</code></p>"}');export{e as data};
